def heap_assending(arr):
    if not arr:
        return []

    heap = arr.copy()
    n = len(heap)

    for i in range(n // 2 - 1, -1, -1):
        _sift_down(heap, n, i)

    result = []
    for i in range(n - 1, -1, -1):
        heap[0], heap[i] = heap[i], heap[0]
        _sift_down(heap, i, 0)
        result.append(heap[i])

