    result = []

    def backtrack(current_perm):
        if len(current_perm) == len(s):
            result.append(current_perm)
            return

        for char in char_count:
            if char_count[char] > 0:
                current_perm += char
                char_count[char] -= 1

                backtrack(current_perm)

                char_count[char] += 1
                current_perm = current_perm[:-1]

    backtrack("")
    return result

